// PaymentProvider.js
import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import PaymentModule from './PaymentModule';

const PaymentContext = createContext(null);

export const PaymentProvider = ({ children, config }) => {
  const [isInitialized, setIsInitialized] = useState(false);
  const [paymentStatus, setPaymentStatus] = useState('idle');
  const [error, setError] = useState(null);

  useEffect(() => {
    initializePayment();
    return () => {
      PaymentModule.disconnect();
    };
  }, []);

  const initializePayment = async () => {
    try {
      await PaymentModule.initialize(config);
      
      PaymentModule.on('success', handlePaymentSuccess);
      PaymentModule.on('failure', handlePaymentFailure);
      PaymentModule.on('cancelled', handlePaymentCancelled);
      
      setIsInitialized(true);
    } catch (err) {
      setError(err.message);
    }
  };

  const handlePaymentSuccess = useCallback((event) => {
    setPaymentStatus('success');
  }, []);

  const handlePaymentFailure = useCallback((event) => {
    setPaymentStatus('failure');
    setError(event.error);
  }, []);

  const handlePaymentCancelled = useCallback((event) => {
    setPaymentStatus('cancelled');
  }, []);

  const processInAppPurchase = useCallback(async (productId, options) => {
    try {
      setPaymentStatus('processing');
      setError(null);
      const result = await PaymentModule.processInAppPurchase(productId, options);
      setPaymentStatus('success');
      return result;
    } catch (err) {
      setPaymentStatus('failure');
      setError(err.message);
      throw err;
    }
  }, []);

  const processCreditCard = useCallback(async (cardData) => {
    try {
      setPaymentStatus('processing');
      setError(null);
      const result = await PaymentModule.processCreditCardPayment(cardData);
      setPaymentStatus('success');
      return result;
    } catch (err) {
      setPaymentStatus('failure');
      setError(err.message);
      throw err;
    }
  }, []);

  const processDigitalWallet = useCallback(async (walletType, paymentData) => {
    try {
      setPaymentStatus('processing');
      setError(null);
      const result = await PaymentModule.processDigitalWalletPayment(walletType, paymentData);
      setPaymentStatus('success');
      return result;
    } catch (err) {
      setPaymentStatus('failure');
      setError(err.message);
      throw err;
    }
  }, []);

  const restorePurchases = useCallback(async () => {
    try {
      return await PaymentModule.restorePurchases();
    } catch (err) {
      setError(err.message);
      throw err;
    }
  }, []);

  const getProducts = useCallback(async (productIds) => {
    try {
      return await PaymentModule.getAvailableProducts(productIds);
    } catch (err) {
      setError(err.message);
      throw err;
    }
  }, []);

  const refundTransaction = useCallback(async (transactionId, amount, reason) => {
    try {
      return await PaymentModule.refundTransaction(transactionId, amount, reason);
    } catch (err) {
      setError(err.message);
      throw err;
    }
  }, []);

  const savePaymentMethod = useCallback(async (paymentMethodData) => {
    try {
      return await PaymentModule.savePaymentMethod(paymentMethodData);
    } catch (err) {
      setError(err.message);
      throw err;
    }
  }, []);

  const getSavedPaymentMethods = useCallback(async () => {
    try {
      return await PaymentModule.getSavedPaymentMethods();
    } catch (err) {
      setError(err.message);
      throw err;
    }
  }, []);

  const processWithSavedMethod = useCallback(async (tokenId, paymentData) => {
    try {
      setPaymentStatus('processing');
      setError(null);
      const result = await PaymentModule.processPaymentWithSavedMethod(tokenId, paymentData);
      setPaymentStatus('success');
      return result;
    } catch (err) {
      setPaymentStatus('failure');
      setError(err.message);
      throw err;
    }
  }, []);

  const value = {
    isInitialized,
    paymentStatus,
    error,
    processInAppPurchase,
    processCreditCard,
    processDigitalWallet,
    restorePurchases,
    getProducts,
    refundTransaction,
    savePaymentMethod,
    getSavedPaymentMethods,
    processWithSavedMethod
  };

  return (
    <PaymentContext.Provider value={value}>
      {children}
    </PaymentContext.Provider>
  );
};

export const usePayment = () => {
  const context = useContext(PaymentContext);
  if (!context) {
    throw new Error('usePayment must be used within PaymentProvider');
  }
  return context;
};


